class GridStackItemResizeWatcher{constructor(t,s,e){this.classToWatch="ui-resizable-resizing",this.targetNode=t,this.onResizeStartedCallback=s,this.onResizeEndedCallback=e,this.observer=null,this.lastClassState=t.classList.contains(this.classToWatch),this.init()}init(){this.observer=new MutationObserver(this.mutationCallback),this.observe()}observe(){this.observer.observe(this.targetNode,{attributes:!0})}disconnect(){this.observer.disconnect()}mutationCallback=t=>{for(let s of t)if("attributes"===s.type&&"class"===s.attributeName){let t=s.target.classList.contains(this.classToWatch);this.lastClassState!==t&&(this.lastClassState=t,t?"function"==typeof this.onResizeStartedCallback&&this.onResizeStartedCallback():"function"==typeof this.onResizeEndedCallback&&this.onResizeEndedCallback())}}}